const MARK_BARS = (
  <>
    <rect x="33" y="34" width="30" height="11" rx="5.5" fill="#E23B2D" />
    <rect x="33" y="56" width="56" height="11" rx="5.5" fill="#F2EFE8" />
    <rect x="33" y="78" width="40" height="11" rx="5.5" fill="#F2EFE8" opacity="0.78" />
  </>
);

function FieldMark({ gradId, stroke }: { gradId: string; stroke: string }) {
  return (
    <>
      <rect x="3" y="3" width="114" height="114" rx="27" fill={`url(#${gradId})`} stroke={stroke} strokeWidth="1.2" />
      {MARK_BARS}
    </>
  );
}

/** Slate logo — lockup, mark, or wordmark. Uses currentColor on the wordmark. */
export function SlateLogo({ variant = 'lockup', height = 26, ...rest }: Props) {
  const uid = useId().replace(/:/g, '');
  const gradId = `slate-logo-grad-${uid}`;
  const stroke = '#3A414F';

  if (variant === 'mark') {
    return (
      <svg viewBox="0 0 120 120" height={height} width={height} xmlns="http://www.w3.org/2000/svg" aria-hidden {...rest}>
        <defs>
          <linearGradient id={gradId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0" stopColor="#2C323D" />
            <stop offset="1" stopColor="#1B1F26" />
          </linearGradient>
        </defs>
        <FieldMark gradId={gradId} stroke={stroke} />
      </svg>
    );
  }

  if (variant === 'wordmark') {
    const w = height * (240 / 82);
    return (
      <svg viewBox="0 0 240 82" height={height} width={w} xmlns="http://www.w3.org/2000/svg" aria-hidden {...rest}>
        <g transform="translate(2,76) scale(0.04901,-0.04901)">
          <path d={WORDMARK} fill="currentColor" />
        </g>
      </svg>
    );
  }

  const width = height * (388 / 120);
  return (
    <svg viewBox="0 0 388 120" height={height} width={width} xmlns="http://www.w3.org/2000/svg" aria-hidden {...rest}>
      <defs>
        <linearGradient id={gradId} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0" stopColor="#2C323D" />
          <stop offset="1" stopColor="#1B1F26" />
        </linearGradient>
      </defs>
      <FieldMark gradId={gradId} stroke={stroke} />
      <g transform="translate(146,97) scale(0.04901,-0.04901)">
        <path d={WORDMARK} fill="currentColor" />
      </g>
    </svg>
  );
}
